question:
What is the output of the following C code snippet? 

c
#include <stdio.h>

int main() {
    int x = 5;
    int y = 10;
    int z = x + y;
    printf("The sum is: %d", z);
    return 0;
}

What is the output of the following C program?

c
#include <stdio.h>

int main() {
    int arr[5] = {10, 20, 30, 40, 50};
    int i, sum = 0;
    for (i = 0; i < 5; i++) {
        if (i % 2 == 0) {
            sum += arr[i];
        }
    }
    printf("%d", sum);
    return 0;
}

What is the output of the following C program segment?

c
#include <stdio.h>

int main() {
    int a = 5;
    int b = 10;
    int c = a + b;
    printf("%d", c);
    return 0;
}

What is the output of the following C program?

c
#include <stdio.h>

int main() {
    int a = 10;
    int b = 20;
    int c = a + b;
    printf("%d", c);
    return 0;
}

explanation:
The given C program segment is as follows: 

c
#include <stdio.h>

int main() {
    int num, output;
    printf("Enter a number: ");
    scanf("%d", &num);
    output = num * 2;
    printf("The output is: %d", output);
    return 0;
}


If the input is 5, the program multiplies this number by 2 and stores it in the variable `output`. The output of the program will be: 

c
The output is: 10


Therefore, the correct answer is 10. Options 25, 50, and 100 are incorrect because they do not match the multiplication operation performed in the program.

question:
What is the output of the following C code snippet when compiled and run?

int main()
{
    int a = 5;
    int b = 2;
    int result = a / b;
    printf("%d", result);
    return 0;
}

What is the output of the following C program snippet?

c
#include <stdio.h>
int main() {
    int a = 10, b = 20, c = 30;
    if (a > b && b > c) {
        printf("A is the largest");
    } else if (b > a && a > c) {
        printf("B is the largest");
    } else if (c > a && a > b) {
        printf("C is the largest");
    }
    return 0;
}

